function ModelPetDreanLand:CheckIsReqInfo()
    if not self:CheckIsOpenGame() then
        return
    end
    self:OnPetDreamLandInfoReq()
    self:CheckIsNeedReqFormation()
end

function ModelPetDreanLand:CheckIsNeedReqFormation()
    local typeList = {}
    local attackCombatType = LCombatTypeConst.COMBAT_TYPE_41
    if gModelFormation:IsFormationEmpty(attackCombatType) then
        table.insert(typeList, attackCombatType)
    end

    local defendCombatType = LCombatTypeConst.COMBAT_TYPE_42
    if gModelFormation:IsFormationEmpty(defendCombatType) then
        table.insert(typeList, defendCombatType)
    end
    if #typeList < 1 then
        return
    end
    gModelFormation:OnGetFormationListReq(typeList)
end

function ModelPetDreanLand:StartCheckInfoTimer()
    if self._checkInfoTimer then
        LxTimer.LoopTimeStop(self._checkInfoTimer)
        self._checkInfoTimer = nil
    end
    self._checkInfoTimer = LxTimer.LoopTimeCall(function()
        self:_OnStartCheckTimer()
    end, 1, false, -1)
end

function ModelPetDreanLand:_OnStartCheckTimer()
    if not self:CheckIsOpenGame() then
        return
    end

    if self._checkDelayTime then
        if Time.time - self._checkDelayTime < 1 then
            return
        end
        self._checkDelayTime = nil
    end

    local nowTime = GetTimestamp()
    local curWeek = LUtil.GetWeekByTime(nowTime)
    local nowTimeTab = LUtil.OSDate("*t", nowTime)
    local curHour = nowTimeTab.hour
    local curMin = nowTimeTab.min
    local curSec = nowTimeTab.sec

    local isOpen = false
    local isMinAndSecFull = curMin == 0 and curSec <= 1
    local needReq = false
    local petDreamlandBegin = self:GetPetDreamlandConfigRefByKey("petDreamlandBegin")
    local begin_week = petDreamlandBegin.week
    local begin_timePoint = petDreamlandBegin.timePoint
    if curWeek == begin_week and curHour == begin_timePoint and isMinAndSecFull then
        isOpen = true

        needReq = true
    end

    local isShutdown = false
    if not needReq then
        local petDreamlandEnd = self:GetPetDreamlandConfigRefByKey("petDreamlandEnd")
        local end_week = petDreamlandEnd.week
        local end_timePoint = petDreamlandEnd.timePoint
        if curWeek == end_week and curHour == end_timePoint and isMinAndSecFull then
            isShutdown = true

            needReq = true
        end
    end

    if LOG_INFO_ENABLED then
        local str = string.replace(">> 周#a1# ~ #a2#点 #a3#分 #a4#秒", curWeek, curHour, curMin, curSec)
        if isOpen then
            str = str .. "，玩法已开启，请求数据~"
        end
        if isShutdown then
            str = str .. "，玩法已关闭，请求数据~"
        end
        printInfoNR2("萌宠幻境玩法检测倒计时：", str)
    end

    if needReq then
        self:CheckIsReqInfo()
        self._checkDelayTime = Time.time
    end
end

