function ModelPetDreanLand:OnPetDreamLandSettlementResp(pb)
    local refId = pb.refId
    local pointId = pb.pointId
    self:DelectPetDreamLandPointData(refId, pointId)

    --- 最终奖励物品列表
    local itemList = self:GetStructRewardItemList(pb.itemList)
    local time = tonumber(pb.time)
    local type = pb.type

    ---@type StructSimplePlayerInfo
    local playerInfo = StructSimplePlayerInfo:New()
    playerInfo:CreateByPb(pb.playerInfos)

    --- 损失奖励信息
    local lostItem = self:GetStructRewardItemList(pb.lostItem)

    self:SetPetDreamLandReportResult({
        refId = refId,
        pointId = pointId,
        itemList = itemList,
        time = time,
        type = type,
        playerInfos = playerInfo,
        lostItem = lostItem,
    })

    local isAutoShow = false
    --- 2024/6/28：自动结算，且在幻境据点界面，需要自动弹窗
    if type == 0 then
        local wndIns = GF.FindFirstWndByName("UIPeWishLandMin")
        if wndIns then
            isAutoShow = true
            gModelPetDreanLand:OpenPetDreamLandReportResult()
        end
    end

    FireEvent(EventNames.PET_DL_POINT_REFRESH)

    FireEvent(EventNames.PDL_REPORTRESULT_STATUS, {
        isAutoShow = isAutoShow,
        type = type,
    })
end

