function ModelPetDreanLand:OnPetDreamLandRecordResp(pb)
    local reportMap = {}
    for i, v in ipairs(pb.rankReport) do
        ---@type StructPetDreamLandRankReport
        local data = gModelPetDreanLand:GetStructPetDreamLandRankReport(v)
        local type = data.type
        local reports = reportMap[type]
        if not reports then
            reports = {}
            reportMap[type] = reports
        end
        table.insert(reports, data)
    end
    self._reportMap = reportMap
end

