---@return table<StructRewardItem>
function ModelPetDreanLand:GetStructRewardItemList(pbRewards)
    ---@type table<StructRewardItem>
    local list = {}
    for i, v in ipairs(pbRewards) do
        ---@type StructRewardItem
        local data = StructRewardItem:New()
        data:CreateByPb(v)
        table.insert(list, data)
    end
    return list
end

--- itemList RewardItem 列表
function ModelPetDreanLand:CommonDisposeRewards(itemList)
    local list = {}

    ---@type table<StructRewardItem>
    local rewardList = self:GetStructRewardItemList(itemList)
    for i, v in ipairs(rewardList) do
        local reward = {
            itemType = v.type,
            itemId = v.itemId,
            itemNum = v.count,
        }
        table.insert(list, {
            reward = reward
        })
    end
    return list
end

