--- 召唤
function ModelPetDreanLand:CommonDisposeRewardCall(pb)
    if self:CheckHasRewardUI() then
        return
    end

    local rewardList = self:CommonDisposeRewards(pb.itemList)

    GF.OpenWndTop("UISdAward", {
        rewardList = rewardList,
        way = ModelHalidom.WAY_REWARD_DRAW,
        luckyItem = pb.extraItem,
        lotteryType = pb.type,
        wndType = 2,
    })
end

function ModelPetDreanLand:CheckHasRewardUI()
    local wndIns = GF.FindFirstWndByName("UISdAward")
    return wndIns ~= nil
end

