function ModelPetDreanLand:CheckIsEnemy(playerId)
    local reportMap = self:GetReportMap()
    if not reportMap then
        return false
    end

    ---@type table<StructPetDreamLandRankReport>
    local defendReports = reportMap[ModelPetDreanLand.TYPE_REPORT_DEFEND]
    if defendReports and #defendReports > 0 then
        ---@param v StructPetDreamLandRankReport
        for i, v in ipairs(defendReports) do
            if v:GetPlayerId() == playerId then
                return true
            end
        end
    end
    return false
end

function ModelPetDreanLand:DisposePetDreamLandLotteryReq(lotteryType, num)
    local reqFunc = function()
        self:OnPetDreamLandLotterytReq(lotteryType, num)
    end
    if self:CheckPetDreamLandHasFree(lotteryType) and num == 1 then
        reqFunc()
        return
    end
    --- 消耗
    local payInfo = self:GetDreamlandCallByType(lotteryType, num)

    --- 幸运值 / 友善值
    local luckyItem = self:GetLuckyItemByLotteryType(lotteryType)

    local itemId = payInfo.itemId
    local payInfoNum = payInfo.itemNum
    local luckyItemNum = luckyItem.itemNum * num
    if gModelItem:GetNumByRefId(itemId) < payInfoNum then
        gModelGeneral:OpenGetWayWnd({ itemId = itemId })
        return
    end

    gModelGeneral:OpenUIOrdinTips({
        refId = 440000,
        para = {
            LUtil.NumberCoversion(payInfoNum),
            gModelItem:GetNameByRefId(itemId),
            LUtil.NumberCoversion(luckyItemNum),
            gModelItem:GetNameByRefId(luckyItem.itemId),
            num
        },
        func = reqFunc
    })
end

