function ModelPetDreanLand:_SplitTime(str)
    local info = string.split(str, "=")
    return {
        week = tonumber(info[1]),
        timePoint = tonumber(info[2])
    }
end

function ModelPetDreanLand:_SplitGrab(str)
    local petDreamlandGrabExpendList = {}
    local petDreamlandGrabExpend = string.split(str, ",")
    for i, v in ipairs(petDreamlandGrabExpend) do
        v = string.split(v, "|")
        local _itemList = LxDataHelper.ParseItem(v[2])
        if _itemList and #_itemList > 0 then
            table.insert(petDreamlandGrabExpendList, {
                time = tonumber(v[1]),
                itemList = _itemList,
            })
        end
    end
    return petDreamlandGrabExpendList
end

function ModelPetDreanLand:_SplitItem(str)
    return LxDataHelper.ParseItem_4(str)
end

function ModelPetDreanLand:_SplitRate(str)
    local list = {}
    local info = string.split(str, ",")
    for i, v in ipairs(info) do
        v = string.split(v, "=")
        table.insert(list, {
            jackpotId = tonumber(v[1]),
            rate = tonumber(v[2])
        })
    end
    return list
end

function ModelPetDreanLand:InitPetDreamlandConfigRef()
    local initPetDreamlandConfigRef = {}
    local ref = GameTable.PetDreamlandConfigRef

    --- 週几=几点开启
    initPetDreamlandConfigRef.petDreamlandBegin = self:_SplitTime(ref.petDreamlandBegin)

    --- 週几=几点关闭
    initPetDreamlandConfigRef.petDreamlandEnd = self:_SplitTime(ref.petDreamlandEnd)

    --- 钻石进攻消耗：按次数顺序配置，实际次数超过最大数的则取最大数的配置，次数|道具格式，多个用,隔开
    initPetDreamlandConfigRef.petDreamlandGrabExpend = self:_SplitGrab(ref.petDreamlandGrabExpend)

    --- 普通奖池，单抽消耗
    initPetDreamlandConfigRef.petDreamlandExpend = self:_SplitItem(ref.petDreamlandExpend)

    --- 普通奖池，多连抽消耗
    initPetDreamlandConfigRef.petDreamlandMoreExpend = self:_SplitItem(ref.petDreamlandMoreExpend)

    --- 普通奖池，每次转动获得的友善值数量
    initPetDreamlandConfigRef.petDreamlandLuckNum = self:_SplitItem(ref.petDreamlandLuckNum)

    --- 奖池权重：小奖池1=权重1，多个用,隔开
    initPetDreamlandConfigRef.petDreamlandRate = self:_SplitRate(ref.petDreamlandRate)

    --- 高级奖池，单抽消耗
    initPetDreamlandConfigRef.petDreamlandHighExpend = self:_SplitItem(ref.petDreamlandHighExpend)

    --- 高级奖池，多连抽消耗
    initPetDreamlandConfigRef.petDreamlandHighMoreExpend = self:_SplitItem(ref.petDreamlandHighMoreExpend)

    --- 高级奖池，每次转动获得的幸运值数量
    initPetDreamlandConfigRef.petDreamlandHighLuckNum = self:_SplitItem(ref.petDreamlandHighLuckNum)

    --- 奖池权重：小奖池1=权重1，多个用,隔开
    initPetDreamlandConfigRef.petDreamlandHighRate = self:_SplitRate(ref.petDreamlandHighRate)

    self._initPetDreamlandConfigRef = initPetDreamlandConfigRef
end

