---@param ref V_PetDreamlandRef
function ModelPetDreanLand:_SplitPetDreamlandRef(ref)
    local reward = LUtil.ConvertCommonItemStrToList(ref.reward)
    --- 图标、数量默认取幻境表[reward]字段的前2个的
    local showRewardList = {}
    for i = 1, 2 do
        table.insert(showRewardList, reward[i])
    end
    return {
        refId = ref.refId,
        num = ref.num,
        name = ccLngText(ref.name),
        reward = reward,
        showRewardList = showRewardList,
        cell = ref.cell,
        bg = ref.bg,
        isLimit = ref.num > 0, --- -1 是无限
    }
end

function ModelPetDreanLand:GetInitPetDreamlandRef()
    local initPetDreamlandRef = self._initPetDreamlandRef
    if not initPetDreamlandRef then
        initPetDreamlandRef = {}
        for k, v in pairs(GameTable.PetDreamlandRef) do
            local reward = LUtil.ConvertCommonItemStrToList(v.reward)
            --- 图标、数量默认取幻境表[reward]字段的前2个的
            local showRewardList = {}
            for i = 1, 2 do
                table.insert(showRewardList, reward[i])
            end
            table.insert(initPetDreamlandRef, self:_SplitPetDreamlandRef(v))
        end
        table.sort(initPetDreamlandRef, function(a, b)
            return a.refId < b.refId
        end)
        self._initPetDreamlandRef = initPetDreamlandRef
    end
    return initPetDreamlandRef
end

function ModelPetDreanLand:GetSplitPetDreamlandRefByRefId(refId)
    if not self._initPetDreamlandRefMap then
        self._initPetDreamlandRefMap = {}
    end
    local initPetDreamlandRef = self._initPetDreamlandRefMap[refId]
    if not initPetDreamlandRef then
        local ref = self:GetPetDreamlandRef(refId)
        initPetDreamlandRef = self:_SplitPetDreamlandRef(ref)
        self._initPetDreamlandRefMap[refId] = initPetDreamlandRef
    end
    return initPetDreamlandRef
end

