------------------------------- PetDreamlandRewardRef start

function ModelPetDreanLand:InitPetDreamlandRewardRef()
    local initPetDreamlandRewardRefMap = {}
    local initPetDreamlandRewardShowMap = {}
    for k, v in pairs(GameTable.PetDreamlandRewardRef) do
        local type = v.type

        local initPetDreamlandRewardRefs = initPetDreamlandRewardRefMap[type]
        if not initPetDreamlandRewardRefs then
            initPetDreamlandRewardRefs = {}
            initPetDreamlandRewardRefMap[type] = initPetDreamlandRewardRefs
        end

        local initPetDreamlandRewardShows = initPetDreamlandRewardShowMap[type]
        if not initPetDreamlandRewardShows then
            initPetDreamlandRewardShows = {}
            initPetDreamlandRewardShowMap[type] = initPetDreamlandRewardShows
        end

        local showInfo

        --- 没配就是不展示
        local show = v.show
        if not string.isempty(show) then
            show = string.split(show, "=")

            local showPos = string.split(show[1], ",")
            local x = showPos[1] or 0
            local y = showPos[2] or 0
            showInfo = {
                showPos = Vector2(x, y),
                scale = tonumber(show[2])
            }
        end

        --- 仅支持单一奖励配置，解析使用列表形式
        local reward = LxDataHelper.ParseItem(v.reward)
        local showReward = reward[1]
        local data = {
            refId = k,
            type = type,
            rewardType = v.rewardType,
            reward = reward,
            showReward = showReward,
            showInfo = showInfo,
            extractRate = v.extractRate,
            extractMin = v.extractMin,
            extractMax = v.extractMax,
            num = v.num,
        }
        if showInfo then
            table.insert(initPetDreamlandRewardShows, data)
        end
        table.insert(initPetDreamlandRewardRefs, data)
    end

    for k, v in pairs(initPetDreamlandRewardRefMap) do
        table.sort(v, function(a, b)
            return a.refId < b.refId
        end)
    end

    self._initPetDreamlandRewardRefMap = initPetDreamlandRewardRefMap
    self._initPetDreamlandRewardShowMap = initPetDreamlandRewardShowMap
end

------------------------------- PetDreamlandRewardRef end



------------------------------- PetDreamlandLuckyRef start

function ModelPetDreanLand:GetPetDreamlandLuckyRefByLottery(lotteryType)
    if not self._initPetDreamlandLuckyRef then
        self._initPetDreamlandLuckyRef = {}
    end
    local lotteryLuckys = self._initPetDreamlandLuckyRef[lotteryType]
    if not lotteryLuckys then
        lotteryLuckys = {}
        local tempList = {}
        for k, v in pairs(GameTable.PetDreamlandLuckyRef) do
            if v.type == lotteryType then
                table.insert(tempList, {
                    refId = k,
                    type = lotteryType,
                    grad = v.grad,
                    gradReward = LxDataHelper.ParseItem_4(v.gradReward),
                })
            end
        end
        table.sort(tempList, function(a, b)
            return a.grad < b.grad
        end)

        local beforeGrad = 0
        local grad = 0
        for i, v in ipairs(tempList) do
            grad = v.grad
            table.insert(lotteryLuckys, {
                refId = v.refId,
                type = lotteryType,
                grad = grad,
                beforeGrad = beforeGrad,
                gradReward = v.gradReward,
            })
            beforeGrad = grad
        end
        self._initPetDreamlandLuckyRef[lotteryType] = lotteryLuckys
    end
    return lotteryLuckys
end


