function ModelPetDreanLand:GetDreamLandTimeStr()
    local timerStr = ""
    if self:DreamLandIsOpen() then
        local endTime = self:GetDreamLandInfoEndTime()
        if endTime and endTime > 0 then
            local timeLeft = endTime - GetTimestamp()
            if timeLeft > 0 then
                timerStr = LUtil.FormatTimeToCn3(timeLeft)
            end
        end
    else
        local ref = gModelDungeonDaily:GetDailyGameConfig(208)
        if ref then
            timerStr = ccLngText(ref.text2)
        end
    end
    return timerStr
end

--- 主入口显示
function ModelPetDreanLand:GetShowDreamLandTimerStr()
    local timerStr = ""
    local isOpen = false
    if self:DreamLandIsOpen() then
        local endTime = self:GetDreamLandInfoEndTime()
        if endTime and endTime > 0 then
            local timeLeft = endTime - GetTimestamp()
            if timeLeft > 0 then
                timerStr = LUtil.FormatTimeToCn3(timeLeft)
            end
        end

        isOpen = true
    else
        local nowTime = GetTimestamp()
        local curWeek = LUtil.GetWeekByTime(nowTime)
        local petDreamlandBegin = self:GetPetDreamlandConfigRefByKey("petDreamlandBegin")
        local begin_week = petDreamlandBegin.week
        local begin_timePoint = petDreamlandBegin.timePoint
        local nextOpenTime = 0
        if curWeek == begin_week then
            nextOpenTime = LUtil.GetNextDayTimes(nil, nil, begin_timePoint)
        else
            nextOpenTime = LUtil.GetWeekTWOTimestamp(nowTime, begin_week, begin_timePoint)
        end
        local timeLeft = nextOpenTime - nowTime
        if timeLeft > 0 then
            timerStr = LUtil.FormatTimeToCn3(timeLeft)
        end
    end

    return timerStr,isOpen
end

function ModelPetDreanLand:GetDreamLandDailyGameStr()
    local timerStr = ""
    ---@type V_DailyGameRef
    local ref = gModelDungeonDaily:GetDailyGameConfig(208)
    if self:DreamLandIsOpen() then
        local endTime = self:GetDreamLandInfoEndTime()
        if endTime and endTime > 0 then
            local timeLeft = endTime - GetTimestamp()
            if timeLeft > 0 then
                timerStr = LUtil.FormatTimespanCn(timeLeft)
                local timeText = ref and ccLngText(ref.timeText)
                if timeText then
                    timerStr = string.replace(timeText, timerStr)
                end
            end
        end
    else
        if ref then
            timerStr = ccLngText(ref.text2)
        end
    end
    return timerStr
end

