function ModelPetDreanLand:OpenPetDreamLandPassByPointId(refId, pointId,isRevenge,playerInd)
    GF.OpenWnd("UIPeWishLandPk", {
        refId = refId,
        pointId = pointId,
        isRevenge = isRevenge,
        playerId = playerInd,
    })
end

--- 无限据点
---@param refId number 据点refId
---@param pointData StructPetDreamLandPointData 据点数据
function ModelPetDreanLand:OpenPetDreamLandNoFightPoint(refId, pointData)
    GF.OpenWnd("UIPeWishLandNoFightPoint", {
        refId = refId,
        pointData = pointData,
    })
end

---@return table 返回当前的进攻消耗
function ModelPetDreanLand:GetCurGrabExpendItems()
    local petDreamlandGrabExpend = self:GetPetDreamlandConfigRefByKey("petDreamlandGrabExpend")
    local len = #petDreamlandGrabExpend
    local curPayGrabNum = self:GetPayTime() + 1
    if curPayGrabNum > len then
        curPayGrabNum = len
    end
    local expendInfo = petDreamlandGrabExpend[curPayGrabNum]
    if not expendInfo then
        return {}
    end
    return expendInfo.itemList
end

function ModelPetDreanLand:ShowVipUpCommonTips(wndNames)
    wndNames = wndNames or {}
    gModelGeneral:OpenUIOrdinTips({
        refId = 80004,
        func = function()
            local wndInst = GF.FindFirstWndByName("UIHuiYPay")
            if not wndInst then
                GF.OpenWndBottom("UIHuiYPay", { page = 2 })
            else
                FireEvent(EventNames.ON_VIPLEVEL_CHANGE)
            end
            for i, v in ipairs(wndNames) do
                GF.CloseWndByName(v)
            end
        end
    })
end

function ModelPetDreanLand:SetPetDreamLandReportResult(argList)
    table.insert(self._settlementFuncs, {
        type = argList.type,
        func = function()
            GF.OpenWnd("UIPeWishLandReportResult", argList)
        end
    })
end

function ModelPetDreanLand:OpenPetDreamLandReportResult()
    if #self._settlementFuncs < 1 then
        return
    end
    local funcInfo = table.remove(self._settlementFuncs, 1)
    self:DoSettlementUI(funcInfo)
end

function ModelPetDreanLand:CheckHasType4SettlementUI()
    if not self._settlementFuncs or #self._settlementFuncs < 1 then
        return
    end
    local index
    for i, v in ipairs(self._settlementFuncs) do
        if v.type == 4 then
            index = i
            break
        end
    end
    if not index then
        return
    end
    local funcInfo = table.remove(self._settlementFuncs, index)
    self:DoSettlementUI(funcInfo)
end

function ModelPetDreanLand:DoSettlementUI(funcInfo)
    local func = funcInfo and funcInfo.func
    if func then
        func()
    end
end

function ModelPetDreanLand:GoToPetDLFormation(formationInfo)
    local cExtraData = formationInfo or {}
    local combatType = cExtraData.combatType
    cExtraData.returnFunc = function()
        gModelGeneral:RecoverGameState()
    end
    gModelGeneral:RecordGameState()
    gLFightManager:PrepareGoToBattle(combatType, cExtraData)
end

function ModelPetDreanLand:CheckPetDreamLandHasFree(lotteryType)
    ---@type StructPetDreamLandLotteryData
    local lotteryData = self:GetTypeLotteryInfo(lotteryType)
    if not lotteryData then
        return false
    end
    local numLeft = lotteryData.totalFreeNum - lotteryData.freeNum
    return numLeft > 0
end

function ModelPetDreanLand:AddBigFightIdAddRewardList(list)
    local rewardList = {}
    local value = self:GetCurBigFightIdPetDreamlandRewardValue()
    if value and #value > 0 then
        for i, v in ipairs(list) do
            local rate = value[i] or 1
            table.insert(rewardList, {
                itemType = v.itemType,
                itemId = v.itemId,
                itemNum = math.floor(v.itemNum * rate),
            })
        end
    else
        rewardList = list
    end
    return rewardList
end

------------------------------------------------------- 红点检测 start
--- 当玩家已参与幻境匹配，处于战斗期且当前未占领任何据点时 每日首次打开界面后红点消失
---@return boolean
function ModelPetDreanLand:CheckFightStateNoOccupyPointRP()
    if not self:DreamLandIsOpen() then
        return false
    end
    return self:CheckIsCanOccupy()
end

---@return boolean 返回所有召唤类型 是否有免费召唤
function ModelPetDreanLand:CheckAllCallHasFreeRP()
    if self:CheckHasFreeByLotteryType(ModelPetDreanLand.TYPE_LOTTERY_0) then
        return true
    end
    if self:CheckHasFreeByLotteryType(ModelPetDreanLand.TYPE_LOTTERY_1) then
        return true
    end
    return false
end

---@return boolean 返回对应召唤类型 是否有免费召唤
function ModelPetDreanLand:CheckHasFreeByLotteryType(lotteryType)
    ---@type StructPetDreamLandLotteryData
    local lotteryData = self:GetTypeLotteryInfo(lotteryType)
    if not lotteryData then
        return false
    end
    return lotteryData.totalFreeNum - lotteryData.freeNum > 0
end

---@return boolean 返回是否已经首次打开
function ModelPetDreanLand:CheckIsFirstOpenLottery(lotteryType)
    return self._lotteryFirstOpenTypeMap[lotteryType]
end

function ModelPetDreanLand:CheckHasLotteryCallItemRP()
    if not self:DreamLandIsOpen() then
        return false
    end
    if self:CheckLotteryItemEnoughByLotteryType(ModelPetDreanLand.TYPE_LOTTERY_0) then
        return true
    end
    if self:CheckLotteryItemEnoughByLotteryType(ModelPetDreanLand.TYPE_LOTTERY_1) then
        return true
    end
    return false
end

function ModelPetDreanLand:CheckLotteryItemEnoughByLotteryType(lotteryType)
    if self._lotteryItemLookMap[lotteryType] then
        return false
    end

    if self:CheckLotteryItemTimesEnoughByLotteryType(lotteryType, 10) then
        return true
    end
    if self:CheckLotteryItemTimesEnoughByLotteryType(lotteryType, 1) then
        return true
    end
    return false
end

function ModelPetDreanLand:CheckLuckHasGet(lotteryType)
    ---@type StructPetDreamLandLotteryData
    local lotteryData = self:GetTypeLotteryInfo(lotteryType)
    if not lotteryData then
        return false
    end
    return lotteryData:CheckLuckHasGet()
end

function ModelPetDreanLand:CheckLotteryItemTimesEnoughByLotteryType(lotteryType, num)
    local payInfo = self:GetDreamlandCallByType(lotteryType, num)
    if payInfo then
        local hasNum = gModelItem:GetNumByRefId(payInfo.itemId)
        return hasNum >= payInfo.itemNum
    end
end

function ModelPetDreanLand:SetLotteryItemLookState(lotteryType)
    if not self._lotteryItemLookMap[lotteryType] then
        if self:CheckLotteryItemTimesEnoughByLotteryType(lotteryType, 10) then
            self._lotteryItemLookMap[lotteryType] = true
        elseif self:CheckLotteryItemTimesEnoughByLotteryType(lotteryType, 1) then
            self._lotteryItemLookMap[lotteryType] = true
        end
    end
    FireEvent(EventNames.REFRESH_PDL_REDPOINT)
end

function ModelPetDreanLand:CheckReportRP()
    if gModelRedPoint:CheckSingle(ModelRedPoint.PDT_NEW_REPORT_1) then
        return true
    end
    if gModelRedPoint:CheckSingle(ModelRedPoint.PDT_NEW_REPORT_2) then
        return true
    end
    return false
end

--- 跳过动画
function ModelPetDreanLand:GetDreamLandCallJumpAniState()
    return checknumber(LPlayerPrefs.PDLCallAniJump) == 1
end


function ModelPetDreanLand:SetDreamLandCallJumpAniState(status)
    local value = status and 1 or 0
    LPlayerPrefs.SetPDLCallAniJump(value)
end

---@return number
function ModelPetDreanLand:CalcSmallFightNum()
    local petDreamlandCoefficient = self:GetPetDreamlandConfigRefByKey("petDreamlandCoefficient")
    local petDreamlandRankCoefficient = self:GetPetDreamlandConfigRefByKey("petDreamlandRankCoefficient")
    local allFightNum = self._allFightNum
    if not allFightNum then
        allFightNum = 0
        local refList = self:GetInitPetDreamlandRef()
        for i,v in ipairs(refList) do
            if v.num > 0 then
                allFightNum = allFightNum + v.num
            end
        end
        self._allFightNum = allFightNum
    end
    local calcNum = allFightNum * petDreamlandCoefficient * petDreamlandRankCoefficient
    return math.floor(calcNum)
end

function ModelPetDreanLand:IsMiniFight()
    local calcNum = self:CalcSmallFightNum()
    local serSmallFightNum = self:GetSmallFightNum()
    return calcNum > serSmallFightNum
end


---@return boolean 是否可偷袭
function ModelPetDreanLand:CheckIsCanSteal(playerId)
    local info = self:GetPetDreamLandInfo()
    if not info then return false end
    return info:CheckIsCanSteal(playerId)
end


--清理工作
--停止计时器之类的
function ModelPetDreanLand:OnModelClear()
    if self._checkInfoTimer then
        LxTimer.LoopTimeStop(self._checkInfoTimer)
        self._checkInfoTimer = nil
    end
end

return ModelPetDreanLand